final:
module RefModule(
    input CLK,
    input RST,
    input CLR,
    input LD,
    input [3:0] DATA,
    output reg [4:0] Q
);reg [3:0] unused_binary_counter;
reg [3:0] async_counter;

always @(posedge CLK) begin
    if (RST) begin
        unused_binary_counter <= 4'b0000;
    end else begin
        unused_binary_counter <= unused_binary_counter + 1;
    end
end

always @(posedge CLK) begin
    if (CLR) begin
        async_counter <= 4'b0000;
    end else if (LD) begin
        async_counter <= DATA;
    end else begin
        async_counter <= async_counter + 1;
    end
end

always @* begin
    Q = unused_binary_counter + async_counter;
end

endmodule
